 15 | pub async fn collect_stream_completion_with_events(
 16 |     mut stream: BoxStream<'static, StreamChunk>,
 17 |     event_tx: Option<&tokio::sync::mpsc::Sender<SessionEvent>>,
 18 | ) -> Result<crate::provider::CompletionResponse> {
 19 |     let mut text = String::new();
 20 |     let mut tools = Vec::<ToolAccumulator>::new();
 21 |     let mut tool_index_by_id = HashMap::<String, usize>::new();
 22 |     let mut usage = Usage::default();
 23 | 
 24 |     while let Some(chunk) = stream.next().await {
 25 |         match chunk {
 26 |             StreamChunk::Text(delta) => {
 27 |                 if delta.is_empty() {
 28 |                     continue;
 29 |                 }
 30 |                 text.push_str(&delta);
 31 |                 if let Some(tx) = event_tx {
 32 |                     let _ = tx.send(SessionEvent::TextChunk(text.clone())).await;
 33 |                 }
 34 |             }
 35 |             StreamChunk::ToolCallStart { id, name } => {
 36 |                 let next_idx = tools.len();
 37 |                 let idx = *tool_index_by_id.entry(id.clone()).or_insert(next_idx);
 38 |                 if idx == next_idx {
 39 |                     tools.push(ToolAccumulator {
 40 |                         id,
 41 |                         name,
 42 |                         arguments: String::new(),
 43 |                     });
 44 |                 } else if tools[idx].name == "tool" {
 45 |                     tools[idx].name = name;
 46 |                 }
 47 |             }
 48 |             StreamChunk::ToolCallDelta {
 49 |                 id,
 50 |                 arguments_delta,
 51 |             } => {
 52 |                 if let Some(idx) = tool_index_by_id.get(&id).copied() {
 53 |                     tools[idx].arguments.push_str(&arguments_delta);
 54 |                 } else {
 55 |                     let idx = tools.len();
 56 |                     tool_index_by_id.insert(id.clone(), idx);
 57 |                     tools.push(ToolAccumulator {
 58 |                         id,
 59 |                         name: "tool".to_string(),
 60 |                         arguments: arguments_delta,
 61 |                     });
 62 |                 }
 63 |             }
 64 |             StreamChunk::ToolCallEnd { .. } => {}
 65 |             StreamChunk::Done { usage: done_usage } => {
 66 |                 if let Some(done_usage) = done_usage {
 67 |                     usage = done_usage;
 68 |                 }
 69 |             }
 70 |             StreamChunk::Error(message) => anyhow::bail!(message),
 71 |         }
 72 |     }
 73 | 
 74 |     let mut content = Vec::new();
 75 |     if !text.is_empty() {
 76 |         content.push(ContentPart::Text { text });
 77 |     }
 78 |     for tool in tools {
 79 |         content.push(ContentPart::ToolCall {
 80 |             id: tool.id,
 81 |             name: tool.name,
 82 |             arguments: tool.arguments,
 83 |             thought_signature: None,
 84 |         });
 85 |     }
 86 | 
 87 |     let finish_reason = if content
 88 |         .iter()
 89 |         .any(|part| matches!(part, ContentPart::ToolCall { .. }))
 90 |     {
 91 |         FinishReason::ToolCalls
 92 |     } else {
 93 |         FinishReason::Stop
 94 |     };
 95 | 
 96 |     Ok(crate::provider::CompletionResponse {
 97 |         message: Message {
 98 |             role: Role::Assistant,
 99 |             content,
100 |         },
101 |         usage,
102 |         finish_reason,
103 |     })
104 | }

